using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    public class FileController : ControllerBase
    {
        [HttpGet("file/{filename}")]
        public async Task<IActionResult> GetFile(string filename)
        {
            // Check if the file exists in the uploads folder
            var filePath = Path.Combine("uploads", filename);
            if (!System.IO.File.Exists(filePath))
            {
                return NotFound();
            }

            // Get the file content and set the appropriate content type
            var fileContent = System.IO.File.ReadAllBytes(filePath);
            var contentType = GetContentType(filename);

            // Return the file content with the appropriate content type
            return File(fileContent, contentType);
        }

        private string GetContentType(string filename)
        {
            // Check if the file is a PDF
            if (filename.EndsWith(".pdf"))
            {
                return "application/pdf";
            }

            // Check if the file is an image
            var extension = Path.GetExtension(filename);
            if (extension != null && extension.StartsWith("."))
            {
                extension = extension.Substring(1);
            }
            if (new string[] { "jpg", "jpeg", "png" }.Contains(extension))
            {
                return "image/" + extension;
            }

            // Return the default content type for all other files
            return "application/octet-stream";
        }
    }
}